mapper.select:
select id, exam_id, student_id, answer_status, create_time, update_time, deleted
from exam_student
where deleted = 0
  and exam_id = #{examId}
  and student_id = #{studentId}
limit 1

mapper.update:
update exam_student
set answer_status = #{answerStatus},
    update_time = now()
where exam_id = #{examId}
  and student_id = #{studentId}
  and deleted = 0
